from TDStoreTools import StorageManager
import TDFunctions as TDF

BitwigBaseExt = \
	mod('bitwigBase/BitwigBaseExt').BitwigBaseExt

CallbacksExt = mod('CallbacksExt').CallbacksExt

class BitwigClipSlotExt(CallbacksExt, BitwigBaseExt):
	"""
	BitwigClipLauncherExt description
	"""
	def __init__(self, ownerComp):

		#CallbacksExt.__init__(self, ownerComp)
		self.CompType = "ClipSlot"
		CallbacksExt.__init__(self, ownerComp)
		BitwigBaseExt.__init__(self, ownerComp)

		#ops
		self.infoCHOP = self.ownerComp.op('clipLauncherInfo')
		# Listener properties

		# special properties to handle
		self.customTrackProperties = ['hasNext', 'hasPrev']
		# synchronized properties

		# propertyInfo [customName, live, mapPar, replyOSC, cast dataType]

		self.propertyInfo = {
			'track' : 
		    	{#'active' 	: [None, True, True, True, 'b'],
				'name' 		: ['Track', False, True, False, None],
				'isPinned' 	: ['Pintrack', False, True, True, 'b'],
				'hasNext' 	: [None, False, False, False, None],
				'hasPrev' 	: [None, False, False, False, None] 
				},
			'clipSlots' :
				{
				'queuedSlotIndex' : [None, True, False, False, None],
				'playingSlotIndex' : [None, True, False, False, None],
				}
		}

		self.BankInfo = {
			'clipSlots' 	: {
				'par' 		: self.ownerComp.par.Clipslot,
				'isDict' 	: True,
				'auxPar'	: None
			}
		}

		# pulseFunctionInfo : <pulseParName> : 
		self.pulseFunctionInfo = {
			'Nexttrack' 			: ['track','selectNext', None], 	
			'Prevtrack' 			: ['track','selectPrev', None],
			'Stopallclips' 			: ['track', 'stop', None],
			'Makevisibleinarranger' : ['track','makeVisibleInArranger', None],
			'Makevisibleinmixer' 	: ['track','makeVisibleInMixer', None],
			'Selectineditor' 		: ['track','selectInEditor', None],
			'Selectinmixer' 		: ['track','selectInMixer', None],
			'Select' 				: ['clipSlots', 'select', 'Clipslot'],
			'Launch'				: ['clipSlots', 'launch', 'Clipslot'],
			'Stop' 					: ['clipSlots', 'stop', 'Clipslot'],
			'Record' 				: ['clipSlots', 'record', 'Clipslot']
		}	

		# properties
		TDF.createProperty(self, 'TrackName', value='', dependable = True,
						   readOnly=False)
		# TDF.createProperty(self, 'ClipName', value='', dependable = True,
		# 				   readOnly=False)
		TDF.createProperty(self, 'ClipSlots', value={}, dependable = 'deep',
						   readOnly = False)
		TDF.createProperty(self, 'QueuedSlotIndex', -1, dependable = True,
						   readOnly=False)
		TDF.createProperty(self, 'PlayingSlotIndex', -1, dependable = True,
						   readOnly=False)

		TDF.createProperty(self, 'clipSlotMenuNames', value=[], dependable = 'deep',
						   readOnly = False)

		#self.resetDockedPosition()
		return

	def setupListeners(self):
		# read through property dict and store listener objects based on 
		# the property information
		BitwigBaseExt.setupListeners(self)

		for context in self.propertyInfo.keys():
			contextInfo = self.propertyInfo[context]

			for property in contextInfo.keys():
				propertyInfo = contextInfo[property]

				customName = propertyInfo[0]
				isLive = propertyInfo[1]
				syncToPar = propertyInfo[2]
				replyOSC = propertyInfo[3]
				castType = propertyInfo[4]

				listener = (self.cursorIndex, context, property)

				if (syncToPar):
					if(customName is not None):
						par = self.ownerComp.par[customName]
					else:
						par = self.ownerComp.par[self.formatString(property)]
				else:
					par = None

				self.addListener(listener, isLive, par, replyOSC, castType)
		return

	def setupPulsePars(self):

		for pName in self.pulseFunctionInfo.keys():
			#check if par exists and is correct type
			if (self.ownerComp.par[pName] is not None):
				pulsePar = self.ownerComp.par[pName]
				if(pulsePar.isPulse):
					pulseInfo = self.pulseFunctionInfo[pName]
					context = pulseInfo[0]
					replyFunction = pulseInfo[1]
					useParData = pulseInfo[2]
					if (useParData is not None):
						if (self.ownerComp.par[useParData] is None):
							print(f"Error! : useParData name {useParData} is invalid")
						else:
							useParData = self.ownerComp.par[useParData]
					cursorIndex = self.cursorIndex
					self.addPulsePar(pulsePar, cursorIndex, context, replyFunction, useParData)
				else:
					print('Error! Parameter: {pName} is not a pulse parameter')
			else:
				print(f"Error! Parameter: {pName} does not exist")

		return

	def onClipStatusChange(self, channel, par, prev):
		try:
			playingSlot = int(self.infoCHOP.chan('*playingSlotIndex'))
		except:
			playingSlot = -1
		try:
			queuedSlot = int(self.infoCHOP.chan('*queuedSlotIndex'))
		except:
			queuedSlot = -1

		# callbacks
		if playingSlot != self.PlayingSlotIndex:
			doCallback = self.ownerComp.par.Enablecallbacks 
			self._PlayingSlotIndex.val = playingSlot
			#self.setClipListeners()
			if doCallback:
				try:
					clipInfo = self.ClipSlots[playingSlot] \
													if playingSlot >=0 else None
				except:
					clipInfo = None
				if clipInfo:
					infoDict = {'name': clipInfo['name'],
								'index': playingSlot}
				else:
					infoDict = {'name': None,
								'index': playingSlot}
				self.DoCallback('onPlayingClipChanged', infoDict)

				if playingSlot == -1:
					self.DoCallback('onClipsStopped')

		if queuedSlot != self.QueuedSlotIndex:
			doCallback = self.ownerComp.par.Enablecallbacks and \
						 not(queuedSlot < 0)
			self._QueuedSlotIndex.val = queuedSlot
			if doCallback:
				try:
					clipInfo = self.ClipSlots[queuedSlot] \
													if queuedSlot >=0 else None
				except:
					clipInfo = None
				if clipInfo:
					infoDict = {'name': clipInfo['name'],
								'index': queuedSlot}
				else:
					infoDict = {'name': None,
								'index': queuedSlot}
				self.DoCallback('onQueuedClipChanged', infoDict)

		return

	def formatClipSlotMenu(self):
		'''
		- called after ClipSlots are updated
		- digests contents of ClipSlots and formats Clip Par Menu
		'''
		menuInfo = []
		slotSize = len(self.ClipSlots)
		for i in range(slotSize):
			if i not in self.ClipSlots.keys():
				continue;
			clipSlot = self.ClipSlots[i]
			name = clipSlot['name']
			hasContent = clipSlot['hasContent']
			labelName = name if hasContent else '(empty)'
			label = f"{i} - {labelName}"
			menuInfo.append(label)

		auxParNames = ['Clipslot', 'Launch', 'Select', 'Stop', 'Record']
		if len(self.ClipSlots) == 0:
			for parName in auxParNames:
				self.ownerComp.par[parName].enable = False
		else:
			for parName in auxParNames:
				self.ownerComp.par[parName].enable = True

		self.clipSlotMenuNames = menuInfo
		return

	def enableClipParameters(self, enable):
		parNames = ['Colorr', 'Colorg','Colorb', 'Synccompcolortoclipcolor', 
